import { useState } from "react";

const QUOTES = [
  { quote: "Das beste Investment das wir für unsere Marke gemacht haben. Die Ergebnisse sprechen für sich.", name: "Clara Hoffmann", company: "Brandhaus GmbH", initials: "CH" },
  { quote: "Innerhalb von drei Monaten haben wir unsere Conversion-Rate verdoppelt. Außergewöhnliche Qualität.", name: "Jonas Müller", company: "ScaleUp AG", initials: "JM" },
  { quote: "Professionell, schnell und immer auf Augenhöhe. Kein anderer Partner kann das bieten.", name: "Petra Wolff", company: "Wolff Studios", initials: "PW" },
];

export default function TestimonialsSingleSpotlight01() {
  const [idx, setIdx] = useState(0);
  const q = QUOTES[idx];
  return (
    <section className="bg-zinc-950 px-6 py-24">
      <div className="mx-auto max-w-3xl text-center">
        <div className="flex justify-center gap-1 text-amber-400 text-xl mb-8">★★★★★</div>
        <blockquote className="text-2xl font-semibold leading-relaxed text-white sm:text-3xl">
          "{q.quote}"
        </blockquote>
        <div className="mt-8 flex items-center justify-center gap-3">
          <div className="flex h-10 w-10 items-center justify-center rounded-full bg-amber-400/20 font-bold text-amber-300">
            {q.initials}
          </div>
          <div className="text-left">
            <p className="text-sm font-semibold text-white">{q.name}</p>
            <p className="text-xs text-zinc-500">{q.company}</p>
          </div>
        </div>
        <div className="mt-8 flex justify-center gap-2">
          {QUOTES.map((_, i) => (
            <button
              key={i}
              onClick={() => setIdx(i)}
              className={`h-2 rounded-full transition-all ${i === idx ? "w-8 bg-amber-400" : "w-2 bg-zinc-700"}`}
            />
          ))}
        </div>
      </div>
    </section>
  );
}

const QUOTES = [
  { name: 'Lena Weber', role: 'COO', quote: 'Strong design consistency and clear communication.' },
  { name: 'David Klein', role: 'CTO', quote: 'The section system scales across teams.' },
  { name: 'Mara Fischer', role: 'Head of Ops', quote: 'Fast updates without visual regressions.' }
];

